INSERT INTO `posts` (`title`, `slug`, `excerpt`, `content`, `cover_image`, `category_id`, `reading_time`, `featured`, `status`, `views`, `published_at`, `created_at`, `updated_at`) VALUES (
  'The Power of the First Step',
  'the-power-of-the-first-step',
  '{\"id\":\"05826520-f433-44ae-9f3e-3c54e81173ef\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":{\"type\":\"text\",\"text\":',
  '[{\"id\":\"05826520-f433-44ae-9f3e-3c54e81173ef\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"How long will it take for you to take a single step and start moving forward?\",\"styles\":{}}],\"children\":[]},{\"id\":\"9f664b90-0814-4d80-8e47-3e7791ee276b\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"We’ve all heard it a thousand times — what matters most is that single first move. That one step forward. It sounds simple enough, doesn’t it? Just start. Just begin. Just do it.\",\"styles\":{}}],\"children\":[]},{\"id\":\"f6e242c3-4b98-4306-8d8d-ea12b02398ff\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"But if it were really that simple, everyone would be doing it.\",\"styles\":{}}],\"children\":[]},{\"id\":\"6e615b3c-0623-4721-9d64-377d781c267f\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(51, 51, 51)\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"Why Starting Feels So Hard\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"9a755cf7-7dbe-40c1-82a8-1cb76be10b82\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Here’s the truth nobody talks about — our minds are designed to resist change. Your brain has spent years adapting to your current routine, your current comfort zone, your current version of life. And the moment you try to step outside of that, your mind raises an alarm. It sees change as danger. Not because it actually \",\"styles\":{}},{\"type\":\"text\",\"text\":\"is\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" dangerous, but because it’s \",\"styles\":{}},{\"type\":\"text\",\"text\":\"unfamiliar\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\".\",\"styles\":{}}],\"children\":[]},{\"id\":\"c2b4d29f-63bd-4c01-8ced-54bedc787ab0\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"That’s just how the brain works. It doesn’t care about your dreams or your ambitions. It cares about keeping you safe. And “safe,” to your brain, means staying exactly where you are.\",\"styles\":{}}],\"children\":[]},{\"id\":\"e29d976d-a9aa-4a5c-8f7b-5eec1d293299\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"But here’s the thing — \",\"styles\":{}},{\"type\":\"text\",\"text\":\"it’s still in your hands to trick your mind.\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\" You can teach it that the unfamiliar isn’t a threat. You can show it that this new path isn’t dangerous — it’s the most comfortable, the most fascinating, the most rewarding thing you’ll ever experience. It takes effort, yes. But it’s possible.\",\"styles\":{}}],\"children\":[]},{\"id\":\"e3a7cf1c-07b4-4b14-911b-f4d3c593b248\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(51, 51, 51)\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"The Step Nobody Talks About\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"84f4e012-2cb0-402c-9988-28b4065c2a1b\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"If you look at any successful person and ask them, \",\"styles\":{}},{\"type\":\"text\",\"text\":\"“What did you do to get where you are today?”\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" — they’ll tell you a lot of things. Hard work. Discipline. Maybe a bit of luck. Maybe family privilege. Maybe the right opportunity at the right time.\",\"styles\":{}}],\"children\":[]},{\"id\":\"429ebe79-feeb-408d-886d-87eccb2ddd32\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"But there’s one thing they often forget to mention — \",\"styles\":{}},{\"type\":\"text\",\"text\":\"the first step they took.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"ec0bf92d-0d7b-42da-8b91-0d179dded9de\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"That quiet, uncertain, slightly terrifying moment when they decided to try. Before the success, before the recognition, before any of it — there was just a person standing at the edge of something unknown, choosing to move forward anyway.\",\"styles\":{}}],\"children\":[]},{\"id\":\"11bca6d2-e234-4ad9-b87c-0a1060122ed6\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"That step rarely makes it into the story. But it’s where every story begins.\",\"styles\":{}}],\"children\":[]},{\"id\":\"68437dc4-f59c-4a82-b58b-1352245f1ba5\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(51, 51, 51)\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"The Sacrifice That Comes With It\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"72fb6b74-cf4a-4ab4-a249-12122aea4a58\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Let’s be honest — this first move doesn’t come free. It comes with sacrifice.\",\"styles\":{}}],\"children\":[]},{\"id\":\"cda8e31a-fb55-4469-8a0f-c198240ad03c\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Maybe it’s the sacrifice of a stable job. Maybe it’s time away from friends. In some situations, it might even mean distance from family. Because when you choose to step into the unknown, there are no guarantees. You don’t know if this step will lead you somewhere meaningful, or if you’ll end up stuck in the middle — with no clear path forward and no easy way back.\",\"styles\":{}}],\"children\":[]},{\"id\":\"98affd17-64c2-412b-8857-262ac09b5110\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"And trust me, that feeling of being stuck in the middle? That’s one of the most unsettling feelings you’ll ever experience.\",\"styles\":{}}],\"children\":[]},{\"id\":\"2e52724d-b8be-4fcc-a63d-4b456a22ef06\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(51, 51, 51)\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"But Life Has a Way\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"84eb5e89-b3e0-4c77-aaa1-189783864b94\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Despite all the uncertainty, despite the fear and the sacrifice, I believe something deeply — \",\"styles\":{}},{\"type\":\"text\",\"text\":\"life will always take you to where you are meant to be.\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\" To the place where you fit. To the version of yourself that you were always supposed to become.\",\"styles\":{}}],\"children\":[]},{\"id\":\"3da510e4-89ae-49b2-ba73-816475552596\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"It’s just up to you to accept it. And to be happy with the journey, even when it doesn’t look the way you imagined.\",\"styles\":{}}],\"children\":[]},{\"id\":\"3f9202f8-8473-40a6-8c59-5a23904cf5ab\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(51, 51, 51)\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"So, Here’s My Ask\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"f72e27d1-2097-4769-b424-02460e16ffed\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"The next time a thought crosses your mind — a new idea, a new dream, a new direction — \",\"styles\":{}},{\"type\":\"text\",\"text\":\"don’t hesitate to take that first step.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"d2b487d9-c276-4428-b00e-3ab16346715c\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"But take it wisely. Calculate the risks. Understand the sacrifices. Know what you might lose and decide if you’re okay with it.\",\"styles\":{}}],\"children\":[]},{\"id\":\"f7e4315a-f30f-4411-80bf-401eced12386\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Because the first step isn’t just about courage. It’s about courage \",\"styles\":{}},{\"type\":\"text\",\"text\":\"and\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" clarity.\",\"styles\":{}}],\"children\":[]},{\"id\":\"53b921be-5498-4e8f-b1a1-cc03e7d7205e\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"rgb(255, 255, 255)\",\"textColor\":\"rgb(33, 33, 33)\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Start moving. But move with your eyes open.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a7d1b5e0-12a6-45be-8bc9-9bd3234e41df\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[],\"children\":[]}]',
  'https://ik.imagekit.io/tapovana/blog/covers/download_di3X43lND.png',
  1,
  3,
  0,
  'published',
  0,
  '2026-03-13 16:32:32',
