INSERT INTO `posts` (`title`, `slug`, `excerpt`, `content`, `cover_image`, `category_id`, `reading_time`, `featured`, `status`, `views`, `published_at`, `created_at`, `updated_at`) VALUES (
  'You\'re Not Lazy. You\'re Overstimulated — Here\'s the Difference',
  'youre-not-lazy-youre-overstimulated-heres-the-difference',
  'You had a full day off. No meetings. No deadlines. Nowhere to be. And yet — you couldn\'t do anything. You scrolled for two hours, couldn\'t finish a show, couldn\'t read, couldn\'t nap. You just... exist',
  '[{\"id\":\"f714e38a-573b-4cc9-a680-cee13d20d778\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You had a full day off.\",\"styles\":{}}],\"children\":[]},{\"id\":\"3a7b37b3-f3ae-4aa6-89f6-2bdfb7976cd1\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"No meetings. No deadlines. Nowhere to be.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a8cfe2a9-2b41-4727-b5c5-8e27e5e1473e\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"And yet — you couldn\'t do anything. You scrolled for two hours, couldn\'t finish a show, couldn\'t read, couldn\'t nap. You just... existed. Uncomfortably. And then at the end of the day, you called yourself lazy and felt guilty about it.\",\"styles\":{}}],\"children\":[]},{\"id\":\"8581eb79-c39a-431c-9bda-42fbf9853552\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"I need you to hear this:\",\"styles\":{}}],\"children\":[]},{\"id\":\"30b9ee17-b574-4759-bf20-5bb459d6518f\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You are probably not lazy. You are most likely overstimulated.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"d22701b9-4fab-4d76-a9ef-dc44ba6e775d\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"And those are two very, very different things.\",\"styles\":{}}],\"children\":[]},{\"id\":\"69fa055b-3f6e-41c1-bc04-969f8402b73c\",\"type\":\"divider\",\"props\":{},\"children\":[]},{\"id\":\"abe914e5-5ee8-42f8-b6bd-65f43e454669\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"What Does \\\"Overstimulated\\\" Actually Mean?\",\"styles\":{}}],\"children\":[]},{\"id\":\"a2e46257-16cb-4124-8d67-c7a1d824472f\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Your brain processes an enormous amount of information every single day. Not just the obvious things — work emails, conversations, tasks — but everything your senses pick up constantly.\",\"styles\":{}}],\"children\":[]},{\"id\":\"af0b9da1-777c-4be5-a91a-9cf8f5cddc74\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Notification sounds. Background music. Bright screens. Crowded spaces. The hum of your fridge. A WhatsApp group with 200 unread messages. News headlines. Instagram reels. Your own looping thoughts.\",\"styles\":{}}],\"children\":[]},{\"id\":\"8bbbea20-ff5e-4929-9f42-9c5f26b27562\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Every single one of these is input. And your brain has to process all of it.\",\"styles\":{}}],\"children\":[]},{\"id\":\"8e2305a5-96ed-4ee0-977b-4c960e3a6648\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Overstimulation happens when your brain takes in more input than it can comfortably process.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"4bbdf681-8ecd-4269-b229-26fed183fe12\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Think of it like a phone with 47 apps open at once. It doesn\'t freeze because it\'s a bad phone. It freezes because it\'s overloaded.\",\"styles\":{}}],\"children\":[]},{\"id\":\"76885dd8-b471-4b64-859f-576431237f82\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"That\'s your brain right now.\",\"styles\":{}}],\"children\":[]},{\"id\":\"90bf7473-5fec-41ab-a2c2-52e1696226b3\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"And when your brain is overloaded, it does something very logical — it shuts down non-essential functions. Motivation. Creativity. The ability to make decisions. Joy. Social energy.\",\"styles\":{}}],\"children\":[]},{\"id\":\"c7df4bc2-e4ef-407d-b428-0c6a1cd602b1\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This is not laziness. This is your nervous system doing exactly what it was designed to do: \",\"styles\":{}},{\"type\":\"text\",\"text\":\"protect you from further overload.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"33b72e87-92b6-43c5-bab5-807770304fa3\",\"type\":\"divider\",\"props\":{},\"children\":[]},{\"id\":\"cbefec39-4029-49e2-bf37-169bdb223c42\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"Laziness vs Overstimulation — How to Tell the Difference\",\"styles\":{}}],\"children\":[]},{\"id\":\"442b82b9-8e48-4b37-8a89-12f897e271d5\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"his is where it gets important, because the symptoms look similar but the cause is completely different.\",\"styles\":{}}],\"children\":[]},{\"id\":\"5a4abfb7-b8f4-4f58-8683-ced489c61bd9\",\"type\":\"table\",\"props\":{\"textColor\":\"default\"},\"content\":{\"type\":\"tableContent\",\"columnWidths\":[null,null,null],\"headerRows\":1,\"rows\":[{\"cells\":[{\"type\":\"tableCell\",\"content\":[],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Laziness\",\"styles\":{\"bold\":true}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Overstimulation\",\"styles\":{\"bold\":true}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]},{\"cells\":[{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Energy\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Generally fine\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Exhausted even without doing much\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]},{\"cells\":[{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Desire\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Don\'t want to do things\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Want\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" to do things but can\'t\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]},{\"cells\":[{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Physical feel\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Comfortable, relaxed\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Restless, tense, or numb\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]},{\"cells\":[{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"After rest\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Feel refreshed\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Feel the same or worse\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]},{\"cells\":[{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Trigger\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"No clear trigger\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Usually after high-input days/weeks\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]},{\"cells\":[{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"Inner voice\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"\\\"I don\'t feel like it\\\"\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}},{\"type\":\"tableCell\",\"content\":[{\"type\":\"text\",\"text\":\"\\\"I want to but I just... can\'t\\\"\",\"styles\":{}}],\"props\":{\"colspan\":1,\"rowspan\":1,\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"}}]}]},\"children\":[]},{\"id\":\"6a8a6476-af93-4cfe-a4ae-d01c846eb1be\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Read that second-to-last row again.\",\"styles\":{}}],\"children\":[]},{\"id\":\"43765fef-4545-445b-89b8-46d14e3cef40\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"f you feel \",\"styles\":{}},{\"type\":\"text\",\"text\":\"the same or worse after resting\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\", that is a huge signal. Laziness is cured by rest. Overstimulation is not cured by passive rest — in fact, scrolling your phone while \\\"resting\\\" often makes it worse, because you\'re still feeding your brain input.\",\"styles\":{}}],\"children\":[]},{\"id\":\"4b1e6652-f5ea-4f0d-92d4-bdb09616e67c\",\"type\":\"divider\",\"props\":{},\"children\":[]},{\"id\":\"74d4b9b2-80ab-4d9e-8db8-92e9c66c3af9\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"7 Signs You\'re Overstimulated (Not Just Tired)\",\"styles\":{}}],\"children\":[]},{\"id\":\"24fa0ffd-feac-47b7-ae43-2ac5e795bc58\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"If you feel \",\"styles\":{}},{\"type\":\"text\",\"text\":\"the same or worse after resting\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\", that is a huge signal. Laziness is cured by rest. Overstimulation is not cured by passive rest — in fact, scrolling your phone while \\\"resting\\\" often makes it worse, because you\'re still feeding your brain input.\",\"styles\":{}}],\"children\":[]},{\"id\":\"641ac31a-194d-42ff-b94b-cc3cad40fb81\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"1. You feel irritable for no clear reason\",\"styles\":{}}],\"children\":[]},{\"id\":\"046115b6-bd14-4cc1-9771-a2c32059e413\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Small things set you off. A noise. Someone chewing. A question you\'d normally answer easily. Your tolerance is basically zero — not because you\'re a bad person, but because your nervous system is already at capacity.\",\"styles\":{}}],\"children\":[]},{\"id\":\"19cff65a-b387-491e-9063-976fe0811f0f\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"2. You can\'t make simple decisions\",\"styles\":{}}],\"children\":[]},{\"id\":\"6b6e02d9-ee67-406b-9ed8-61dc67cbff7a\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"What to eat. What to watch. What to reply. Even tiny decisions feel genuinely hard. This is called \",\"styles\":{}},{\"type\":\"text\",\"text\":\"decision fatigue\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\", and it\'s a direct symptom of an overstimulated brain.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a00e459a-b43e-4412-9da4-b6e65befb81c\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"3. You want to do things but can\'t start\",\"styles\":{}}],\"children\":[]},{\"id\":\"815bee4a-c377-4d14-88fb-9d73bf855ca3\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This is the most misunderstood one. You genuinely want to read that book. You want to call your friend. You want to work on your project. But you sit down and just... stare. This is not lack of motivation. This is a nervous system in protective shutdown.\",\"styles\":{}}],\"children\":[]},{\"id\":\"efb1187c-2291-4c0c-b297-1a09223896a6\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"4. Crowds and noise feel unbearable\",\"styles\":{}}],\"children\":[]},{\"id\":\"7f22bb1b-2f2b-4f5f-b768-f88243cd6430\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You used to be okay in busy spaces. Now a loud restaurant, a full train, or even a group call leaves you feeling wrung out. Sensory input that was once manageable now feels too loud, too much, too fast.\",\"styles\":{}}],\"children\":[]},{\"id\":\"f6f7c7c0-b120-4286-9759-773be78a0def\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\". You\'re consuming but not enjoying\",\"styles\":{}}],\"children\":[]},{\"id\":\"0c48f7f4-259c-4343-a9f9-4783e7db73a9\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You\'re watching a show but not really watching it. Eating but not tasting. Scrolling but not registering anything. You\'re going through the motions of enjoyment without actually feeling it. This is emotional numbness — a hallmark of overstimulation.\",\"styles\":{}}],\"children\":[]},{\"id\":\"4a49b5e6-a550-4068-ae51-f672dd35036a\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"6. Your sleep is restless even when you\'re exhausted\",\"styles\":{}}],\"children\":[]},{\"id\":\"1cfbec38-6c91-4484-bc9d-d3841d9c2006\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You\'re tired but you can\'t fall asleep easily. Or you sleep for 9 hours and wake up tired. An overstimulated nervous system stays in a low-grade alert state — making deep, restorative sleep harder to reach.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a35a7db1-9e82-48b0-8e65-d7bbcab56485\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"7. You feel guilty about feeling this way\",\"styles\":{}}],\"children\":[]},{\"id\":\"1a3c581f-860b-4a84-8cb0-f0a7ba325128\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This one\'s sneaky. Because when you\'re overstimulated and can\'t function well, your inner critic often shows up loudly: \",\"styles\":{}},{\"type\":\"text\",\"text\":\"\\\"Why are you like this? What\'s wrong with you? You should be doing more.\\\"\",\"styles\":{\"italic\":true}}],\"children\":[]},{\"id\":\"98b04b39-5673-4b41-ba2a-e944af913745\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"That guilt adds more stress. Which creates more overstimulation. Which creates more shutdown. It\'s a cycle.\",\"styles\":{}}],\"children\":[]},{\"id\":\"d9a204cc-5cfd-4570-9ffc-fa42668938b5\",\"type\":\"divider\",\"props\":{},\"children\":[]},{\"id\":\"fd8b8fa8-c895-42c7-8392-6cf6df6028da\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"Why This Is Happening More Than Ever\",\"styles\":{}}],\"children\":[]},{\"id\":\"2efc7122-1add-4be4-b443-5a788f94d71d\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Let me be honest — this is not just a personal failing. This is a systemic problem.\",\"styles\":{}}],\"children\":[]},{\"id\":\"e3130114-18c5-41d8-8de0-a6719cc7f980\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"The average person in 2026 checks their phone \",\"styles\":{}},{\"type\":\"text\",\"text\":\"96 times a day.\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\" That\'s once every 10 minutes. We receive an estimated \",\"styles\":{}},{\"type\":\"text\",\"text\":\"34 gigabytes of information\",\"styles\":{\"bold\":true}},{\"type\":\"text\",\"text\":\" daily — five times more than people received in 1986.\",\"styles\":{}}],\"children\":[]},{\"id\":\"7cd0f850-59d8-4966-9d98-d2f06dee5c5a\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"We were not built for this.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a3b4d9df-0b22-4be9-80c8-0e34ca0885f1\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Our nervous systems evolved over hundreds of thousands of years in a world where information came slowly — a conversation, a sunset, a fire crackling. The modern world moves at a speed our biology simply hasn\'t caught up to.\",\"styles\":{}}],\"children\":[]},{\"id\":\"1d5a050e-dcd2-48ce-9408-fdec28cf4be8\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Add to that: the pressure to be constantly productive, to respond instantly, to stay informed about every global crisis, to maintain a curated presence online, to never really switch off —\",\"styles\":{}}],\"children\":[]},{\"id\":\"1edde5d4-b82a-44f2-93d1-99bd76782f12\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"And you have a generation of people whose baseline state is overstimulation.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a5e73145-ea77-4f97-8b45-dbd5ba154eae\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You are not broken. You are living in a world that is genuinely too loud.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"642b6fa4-549c-486f-85df-8e022fd852f2\",\"type\":\"divider\",\"props\":{},\"children\":[]},{\"id\":\"667b8d2f-8f18-436c-a79b-b6aa350621af\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"How to Calm an Overstimulated Nervous System\",\"styles\":{}}],\"children\":[]},{\"id\":\"2c7d533a-eaa3-4864-a0be-379cb484871e\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This is the practical part. And I want to be clear — these are not \\\"self-care tips.\\\" These are specific inputs that signal safety to your nervous system.\",\"styles\":{}}],\"children\":[]},{\"id\":\"25434bc6-e5b8-49e4-b1bb-ab29ad9f2615\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"1. Reduce Input Before You Add Anything\",\"styles\":{}}],\"children\":[]},{\"id\":\"e7911dfa-f915-4b2e-91dd-8c48fd2de9fe\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"The instinct is to \",\"styles\":{}},{\"type\":\"text\",\"text\":\"do\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" something to feel better — exercise, call a friend, make a plan. But when you\'re overstimulated, the first move is subtraction, not addition.\",\"styles\":{}}],\"children\":[]},{\"id\":\"484415b2-3e84-4fdb-9673-f008b95f04e9\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Turn off notifications for 2 hours\",\"styles\":{}}],\"children\":[]},{\"id\":\"e9c73b97-b6bf-4b5c-8a08-d8919fede78d\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Put your phone in another room\",\"styles\":{}}],\"children\":[]},{\"id\":\"1e7dcf39-b6a5-48fe-9e1b-46f9a4a3399c\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Sit in a quiet room without music, podcasts, or screens\",\"styles\":{}}],\"children\":[]},{\"id\":\"8e8b5e57-19f3-4bf7-85a7-915c6be3d4bf\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Close browser tabs you don\'t need right now\",\"styles\":{}}],\"children\":[]},{\"id\":\"a29d4012-4644-48a3-8302-6b69bbe877ed\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Silence is not nothing. Silence is input reduction. It is medicine.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"799da8b0-dfdd-4083-bc6d-2109ab5cfce3\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"2. Slow, Deep Breathing — Specifically This Pattern\",\"styles\":{}}],\"children\":[]},{\"id\":\"c4bcec50-9342-49ec-a7b4-7532fc2a8af7\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Not just any breathing. The physiological sigh — a double inhale through the nose followed by a long exhale through the mouth — is the fastest scientifically documented way to downregulate the nervous system.\",\"styles\":{}}],\"children\":[]},{\"id\":\"ff764140-af45-4a61-9ebd-89c8be625709\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Try it now:\",\"styles\":{}}],\"children\":[]},{\"id\":\"d5faac7d-1482-4b53-8757-4c47553265c2\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Inhale through your nose\",\"styles\":{}}],\"children\":[]},{\"id\":\"5c36084d-775f-4742-9616-dc644438ffe2\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"At the top, sniff a little more air in\",\"styles\":{}}],\"children\":[]},{\"id\":\"0420a50f-9b35-4836-85f8-ab813caeca52\",\"type\":\"bulletListItem\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Exhale slowly and fully through your mouth\",\"styles\":{}}],\"children\":[]},{\"id\":\"81835a2d-6047-4998-b48c-b86df0d9d775\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Do this 3 times. Notice the shift.\",\"styles\":{}}],\"children\":[]},{\"id\":\"d4dedce2-7a39-42b9-a71a-d12572daa46e\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This was validated by research from Stanford neuroscientist Andrew Huberman and published in \",\"styles\":{}},{\"type\":\"text\",\"text\":\"Cell Reports Medicine\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" in 2023.\",\"styles\":{}}],\"children\":[]},{\"id\":\"db289d66-3859-4989-8e3d-45155811cc07\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"3. Get Outside — Without Your Phone\",\"styles\":{}}],\"children\":[]},{\"id\":\"c43876ce-fa7c-46c5-b3fd-40a7a93db6b9\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Natural environments are one of the most powerful nervous system regulators we have access to. Sunlight, green spaces, the sound of wind or water — these are ancient signals to your brain that you are safe.\",\"styles\":{}}],\"children\":[]},{\"id\":\"380f503f-3843-448b-86e9-7b1a3a40af38\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"A 20-minute walk outside (without earphones, without your phone) can meaningfully reduce cortisol levels and quiet mental noise.\",\"styles\":{}}],\"children\":[]},{\"id\":\"87da3ecc-62dc-41ba-800d-5890cd73b4c0\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"You don\'t need a forest. A street with trees works. A balcony works. Even sitting by an open window facing outside works.\",\"styles\":{}}],\"children\":[]},{\"id\":\"169228d0-1d06-480c-a1a9-5ece3a92a69a\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"4. Do One Thing With Your Hands\",\"styles\":{}}],\"children\":[]},{\"id\":\"62c63a90-adf8-4c60-8ae9-41429be2c468\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Cooking something simple. Watering your plants. Knitting. Drawing badly. Folding laundry.\",\"styles\":{}}],\"children\":[]},{\"id\":\"85d82bfb-976b-47be-b330-dd26e217f66a\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Manual, repetitive, low-stakes physical tasks are extraordinary for an overstimulated mind. They give your brain something gentle to focus on while allowing your nervous system to downshift.\",\"styles\":{}}],\"children\":[]},{\"id\":\"850997f3-eb88-4c66-80a1-8644d05bab5d\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This is why so many people find cooking oddly therapeutic, or why you suddenly feel better after reorganizing a drawer. It\'s not procrastination. It\'s nervous system regulation.\",\"styles\":{}}],\"children\":[]},{\"id\":\"414a237b-464a-45a1-bba5-0cfaf93673da\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":3,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"5. Give Yourself a No-Input Window Daily\",\"styles\":{}}],\"children\":[]},{\"id\":\"975a037d-faa0-4a55-8706-2d2d8f101fe0\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"This is the long-term fix.\",\"styles\":{}}],\"children\":[]},{\"id\":\"8423eacb-37e4-4357-a4b4-8a0609a78929\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Even 20–30 minutes a day with zero input — no phone, no music, no content, no conversation — gives your nervous system time to process, consolidate, and reset.\",\"styles\":{}}],\"children\":[]},{\"id\":\"273ada34-a85e-42b6-b8d0-9bf05af514ea\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"It feels uncomfortable at first. Sit with that discomfort. It gets easier. And over time, your baseline tolerance for stimulation improves.\",\"styles\":{}}],\"children\":[]},{\"id\":\"5a939065-f798-4ee0-8d9e-1e072f677247\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Think of it like giving your overloaded phone time to close background apps.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a79187f4-e19b-48ce-ab70-c595595c7290\",\"type\":\"divider\",\"props\":{},\"children\":[]},{\"id\":\"f8f6d654-3820-4841-aeca-57fc735d3de8\",\"type\":\"heading\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\",\"level\":2,\"isToggleable\":false},\"content\":[{\"type\":\"text\",\"text\":\"A Note on Shame\",\"styles\":{}}],\"children\":[]},{\"id\":\"51593583-f8d6-439a-a7af-550944f7893d\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"I want to end here because I think it matters.\",\"styles\":{}}],\"children\":[]},{\"id\":\"824440d2-fa1a-49a9-8b5e-2101d49eb989\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"The narrative around productivity and motivation in our culture is deeply unkind. We celebrate busyness. We pathologize rest. We call people who can\'t keep up \\\"lazy\\\" — and worse, we call \",\"styles\":{}},{\"type\":\"text\",\"text\":\"ourselves\",\"styles\":{\"italic\":true}},{\"type\":\"text\",\"text\":\" that.\",\"styles\":{}}],\"children\":[]},{\"id\":\"a627411b-0738-45c8-a870-e569e51ddedf\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"But the truth is that most people who struggle to function aren\'t lacking discipline. They\'re running on a nervous system that has been pushed past its limits, often for a very long time, with very little understanding of why.\",\"styles\":{}}],\"children\":[]},{\"id\":\"438aeafe-d98e-4eef-a563-ba256bc2c067\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Knowing this doesn\'t fix everything. But it changes where you direct your energy.\",\"styles\":{\"bold\":true}}],\"children\":[]},{\"id\":\"2d5758f6-538f-45f8-88c6-d61572ccc201\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"Instead of fighting yourself for being \\\"lazy,\\\" you start asking: \",\"styles\":{}},{\"type\":\"text\",\"text\":\"What does my nervous system need right now?\",\"styles\":{\"italic\":true}}],\"children\":[]},{\"id\":\"83e594ab-07fa-4cc9-8384-e7df6130445f\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"That single shift — from self-judgment to genuine self-inquiry — is where things start to change.\",\"styles\":{}}],\"children\":[]},{\"id\":\"0cd8782b-9682-4066-8c34-cc201501f470\",\"type\":\"paragraph\",\"props\":{\"backgroundColor\":\"default\",\"textColor\":\"default\",\"textAlignment\":\"left\"},\"content\":[],\"children\":[]}]',
